"use client";
import React, { useState } from "react";
import { supabase } from "../../database/supabaseClient";

// ======================================================
// 🧰 CORRUPTION, HEALING, SESSION UTILITIES
// ======================================================

// Create the corruption exactly like the system failure
function corruptSupabaseStorage() {
  console.warn("💥 Simulating REAL corruption (race condition)…");

  // 1. Write a valid session
  const fake = {
    currentSession: {
      expires_at: Date.now() / 1000 + 3600,
      access_token: "FOO",
      refresh_token: "BAR",
    },
    expiresAt: Date.now() + 3600,
  };

  localStorage.setItem("sb-sb-auth-token", JSON.stringify(fake));

  // 2. Simulate Supabase auto-refresh firing at the same time
  // (write half of a session object)
  setTimeout(() => {
    console.warn("💥 Injecting half-written session…");

    localStorage.setItem("sb-sb-auth-token", "{bad_json:");
  }, 5);

  // 3. Simultaneously delete during login (replicate your original bug)
  setTimeout(() => {
    console.warn("💣 Login page wiping keys at same moment…");
    localStorage.removeItem("sb-sb-auth-token");
  }, 5);
}

// Remove only corrupted keys
function repairSupabaseStorage() {
  const keys = Object.keys(localStorage);
  let repaired = false;

  keys.forEach((key) => {
    if (
      key === "sb-sb-auth-token" ||
      key.includes("undefined") ||
      key.includes("null") ||
      (key.startsWith("sb-") && !key.includes("-auth-token"))
    ) {
      console.warn("🛑 Deleting corrupted key:", key);
      localStorage.removeItem(key);
      repaired = true;
    } else if (key.startsWith("sb-")) {
      try {
        JSON.parse(localStorage.getItem(key) || "");
      } catch {
        console.warn("🛑 Invalid JSON in:", key);
        localStorage.removeItem(key);
        repaired = true;
      }
    }
  });

  return repaired;
}

// Remove all Supabase keys
function nukeSupabaseStorage() {
  const keys = Object.keys(localStorage);
  keys.forEach((k) => {
    if (k.startsWith("sb-")) {
      console.warn("💣 Removing Supabase key:", k);
      localStorage.removeItem(k);
    }
  });
}


// ======================================================
// 🔐 TEST USERS (example only)
// ======================================================
const USERS = [
  {
    label: "User1",
    email: "user1@test.com",
    password: "password1",
  },
  {
    label: "User2",
    email: "user2@test.com",
    password: "password1",
  },
] as const;


// ======================================================
// 🔬 PAGE COMPONENT
// ======================================================
export default function AuthDebugger() {
  const [log, setLog] = useState<string[]>([]);
  const append = (msg: string) =>
    setLog((prev) => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);

  // -----------------------------------------------------
  // 🔍 Step 1 — Test: corrupt storage
  // -----------------------------------------------------
  const testCorrupt = () => {
    corruptSupabaseStorage();
    append("💥 Created corrupted Supabase storage entries.");
  };

  // -----------------------------------------------------
  // 🔍 Step 2 — Test: repair storage
  // -----------------------------------------------------
  const testRepair = () => {
    const fixed = repairSupabaseStorage();
    append(fixed ? "🛠 Repaired storage!" : "👌 Nothing to repair.");
  };

  // -----------------------------------------------------
  // 🔍 Step 3 — Test: Nuke all session
  // -----------------------------------------------------
  const testNuke = () => {
    nukeSupabaseStorage();
    append("💣 Nuked all Supabase storage keys.");
  };

  // -----------------------------------------------------
  // 🔍 Step 4 — Test: Login
  // -----------------------------------------------------
  const testLogin = async (user: (typeof USERS)[number]) => {
    append(`\n=== 🔐 LOGIN TEST (${user.label}) ===`);

    const { error } = await supabase.auth.signInWithPassword({
      email: user.email,
      password: user.password,
    });

    if (error) {
      append(`❌ Login error: ${error.message}`);
      return;
    }

    append(`✅ Logged in as ${user.email}`);

    const { data } = await supabase.auth.getSession();
    append("📦 Session after login:");
    append(JSON.stringify(data, null, 2));
  };

  // -----------------------------------------------------
  // 🔍 Step 5 — Test: Session call
  // -----------------------------------------------------
  const testGetSession = async () => {
    append("🔍 Fetching session…");
    const { data, error } = await supabase.auth.getSession();
    if (error) append("❌ " + error.message);
    append(JSON.stringify(data, null, 2));
  };

  // -----------------------------------------------------
  // 🔍 Step 6 — Test: Logout
  // -----------------------------------------------------
  const testLogout = async () => {
    append("🚪 Logout test started…");

    // Nuke storage first (simulate corrupted logout)
    nukeSupabaseStorage();

    const { error } = await supabase.auth.signOut();

    if (error) {
      append("❌ Logout failed: " + error.message);
      return;
    }

    append("✅ Successfully logged out and wiped storage.");
  };

  // -----------------------------------------------------
  // 🔍 Step 7 — Test: Auto-Repair on Delay
  // -----------------------------------------------------
  const testTimedRepair = () => {
    append("⏳ Setting auto-repair timer (5s)…");
    setTimeout(() => {
      const repaired = repairSupabaseStorage();
      append(repaired ? "🛠 Timer repair executed" : "👌 Timer found no corruption");
    }, 5000);
  };

  // -----------------------------------------------------
  // 🔍 Step 8 — Inspect localStorage
  // -----------------------------------------------------
  const inspectStorage = () => {
    append("📦 Current localStorage:");
    append(JSON.stringify(Object.keys(localStorage), null, 2));
  };


  // ======================================================
  // 🎨 UI
  // ======================================================
  return (
    <div
      style={{
        padding: 20,
        color: "white",
        background: "#111",
        fontFamily: "monospace",
        minHeight: "100vh",
      }}
    >
      <h1>🧪 Supabase Auth Debugger</h1>
      <p>Use this page to break, inspect, repair, and test Supabase auth.</p>

      <h2>🔧 Actions</h2>

      <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
        <button onClick={testCorrupt}>💥 Corrupt Storage</button>
        <button onClick={testRepair}>🛠 Repair Storage</button>
        <button onClick={testNuke}>💣 Nuke Storage</button>
        <button onClick={inspectStorage}>📦 Inspect Storage</button>
        <button onClick={testGetSession}>🔍 Get Session</button>
        <button onClick={testLogout}>🚪 Logout</button>
        <button onClick={testTimedRepair}>⏳ Timed Repair</button>
      </div>

      <h2>🔐 Login Tests</h2>

      <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
        {USERS.map((u) => (
          <button key={u.label} onClick={() => testLogin(u)}>
            Login as {u.label}
          </button>
        ))}
      </div>

      <pre
        style={{
          marginTop: 20,
          background: "#000",
          padding: 15,
          borderRadius: 8,
          height: 500,
          overflowY: "auto",
          fontSize: 12,
        }}
      >
        {log.join("\n")}
      </pre>
    </div>
  );
}
